('prophecy', 'Prophecy', 'Monster', 'Ancient Prophecy is a Booster Pack in the Yu-Gi-Oh! Official Card Game (OCG) and Yu-Gi-Oh! Trading Card Game (TCG). It is the fifth set of the OCGs sixth series. It is followed by Stardust Overdrive.', 'unknown', 'mixed', 'needs_review', timezone('utc', now()), 'Backfilled from Yu-Gi-Oh Wiki/Fandom.', 19, false, null, null, '', 0, null, null, ARRAY[]::text[], null, 0, 0, null, 'Booster Pack', 'Booster Pack', ARRAY[]::text[], null, false, ARRAY[]::text[], null, null, ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], 'implemented', null),
('psychic-armor-head', 'Psychic Armor Head', 'Monster', 'Instead of drawing a card in your Draw Phase, you may take 1 Armor monster from your Deck and add it to your Hand. If this card is in the Graveyard, you may Special Summon it to the Field in face-up Attack Position during your Standby Phase. (Only one Armor monster can attack per turn. If there are 2 or more Armor monsters on your Field and an Armor monster is the target of an attack, the controller of that Armor monster can change the target of the attack to any of the Armor monsters they control).', 'custom', 'mixed', 'needs_review', timezone('utc', now()), 'Backfilled from Yu-Gi-Oh Wiki/Fandom.', 19, false, null, null, 'Earth', 4, null, null, ARRAY[]::text[], null, 0, 500, null, 'Machine / Armor', 'Machine', ARRAY['Armor']::text[], null, false, ARRAY[]::text[], null, null, ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], 'partial', null),
('pumpking-the-king-of-ghosts', 'Pumpking the King of Ghosts', 'Monster', 'Gains 100 ATK/DEF while "Castle of Dark Illusions" is on the field. Also, during your Standby Phase, if "Castle of Dark Illusions" is on the field: This card gains 100 ATK/DEF. This effect activates once per turn, for four of your Standby Phases (counting this as the first). "Castle of Dark Illusions" must be on the field to activate and to resolve this effect. If "Castle of Dark Illusions" is not on the field, this ATK/DEF gain disappears and this effect resets.', 'official', 'mixed', 'verified', timezone('utc', now()), 'Merged from local CSV and verified external card data.', 19, true, '29155212', null, 'DARK', 6, null, null, ARRAY[]::text[], null, 1800, 2000, null, 'Effect Monster', 'Zombie', ARRAY['Effect']::text[], null, false, ARRAY[]::text[], null, null, ARRAY['Castle of Dark Illusions']::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY['Continuous']::text[], 'partial', null),
('purity-of-the-cemetery', 'Purity of the Cemetery', 'Monster', 'Activate only if you have no monsters in your Graveyard. During each of your opponent''s Standby Phases, inflict 100 damage to your opponent for each monster in your opponent''s Graveyard. If there is a Monster Card in your Graveyard, destroy this card.', 'anime', 'mixed', 'needs_review', timezone('utc', now()), 'Backfilled from Yu-Gi-Oh Wiki/Fandom.', 19, false, null, null, '', 0, null, null, ARRAY[]::text[], null, 0, 0, 'Continuous', null, null, ARRAY[]::text[], 'Continuous', false, ARRAY[]::text[], null, null, ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], 'partial', null),
