('twin-bow-centaur', 'Twin Bow Centaur', 'Monster', 'You cannot declare an attack during the turn you activate this card''s effect. Once per turn, you can select 1 monster you control and 1 monster your opponent controls, then toss a coin. ● If you call it right: Remove from play the monster your opponent controls, and inflict damage to your opponent equal to the original ATK of that monster. ● If you call it wrong: Remove from play the monster you control, and take damage equal to the original ATK of that monster.', 'anime', 'mixed', 'needs_review', timezone('utc', now()), 'Backfilled from Yu-Gi-Oh Wiki/Fandom.', 24, false, null, null, '', 0, null, null, ARRAY[]::text[], null, 0, 0, 'Continuous', null, null, ARRAY[]::text[], 'Continuous', false, ARRAY[]::text[], null, null, ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], 'partial', null),
('twin-headed-behemoth', 'Twin-Headed Behemoth', 'Monster', 'During the End Phase, if this card is in the GY because it was destroyed on the field and sent there this turn: You can Special Summon this card, but its ATK/DEF become 1000. You can only use this effect of "Twin-Headed Behemoth" once per Duel.', 'official', 'mixed', 'verified', timezone('utc', now()), 'Merged from local CSV and verified external card data.', 24, true, '43586926', null, 'WIND', 3, null, null, ARRAY[]::text[], null, 1500, 1200, null, 'Effect Monster', 'Dragon', ARRAY['Effect']::text[], null, false, ARRAY[]::text[], null, null, ARRAY[]::text[], ARRAY[]::text[], ARRAY['Activates from your Graveyard']::text[], ARRAY['Trigger', 'Condition']::text[], 'partial', null),
