insert into public.characters (
  id,
  name,
  intro_line,
  forfeit_line,
  stage_clear_line,
  defeat_line,
  signature_card_ids,
  ai_profile,
  voice_profile
)
values
('char_joey', 'Joey Wheeler', 'Joey grins. "This is my kind of duel!"', 'Joey leans in. "C''mon, you can''t bail now. Leave and I''m takin'' this one by forfeit."', 'Joey laughs it off, but you clearly took the momentum away from him.', 'Joey rode the chaos and pushed you out of the ladder this round.', ARRAY['time-wizard', 'jinzo', 'thousand-dragon']::text[], '{"aggression":1.25,"signatureWeight":1.1,"removalBias":0.75,"backrowBias":0.2,"comebackBias":0.8}'::jsonb, '{"intro":"Joey grins. \"This is my kind of duel!\"","summon":"Joey pumps a fist. \"Get in there and swing hard!\"","spell":"Joey slams a card down. \"Time for one of my wild cards!\"","trap":"Joey smirks. \"Bet ya did not see that comin''!\"","attack":"Joey points forward. \"Go on, finish the job!\"","turn":"Joey draws fast. \"My move now!\"","loss":"Joey exhales. \"Aw, man... you got me that time.\"","forfeit":"Joey leans in. \"C''mon, you can''t bail now. Leave and I''m takin'' this one by forfeit.\""}'::jsonb),
('char_mai', 'Mai Valentine', 'Mai smiles. "Try to keep up with me."', 'Mai smiles faintly. "Leaving already? If you walk away now, this duel is mine."', 'Mai gives a measured nod. You outplayed her cleanly.', 'Mai kept control of the duel and punished every opening you gave her.', ARRAY['harpie-lady-sisters', 'harpie-s-feather-duster', 'mirror-wall']::text[], '{"aggression":0.7,"signatureWeight":0.8,"removalBias":0.8,"backrowBias":1.1,"comebackBias":0.5}'::jsonb, '{"intro":"Mai smiles. \"Try to keep up with me.\"","summon":"Mai flicks her card forward. \"Grace beats brute force every time.\"","spell":"Mai tilts her head. \"A smart duelist always keeps a trick ready.\"","trap":"Mai laughs softly. \"Walked right into it.\"","attack":"Mai gives a calm nod. \"Now strike.\"","turn":"Mai draws with confidence. \"Watch closely.\"","loss":"Mai folds her arms. \"Not bad. You earned that win.\"","forfeit":"Mai smiles faintly. \"Leaving already? If you walk away now, this duel is mine.\""}'::jsonb),
('char_pegasus', 'Maximillion Pegasus', 'Pegasus smiles. "Welcome to my delightful little performance."', 'Pegasus chuckles. "Ending the show so soon? If you exit now, I shall gladly accept the forfeit."', 'Pegasus applauds the upset. You broke through his tricks and stole the stage.', 'Pegasus turned the duel into his showpiece and you never regained the tempo.', ARRAY['relinquished', 'toon-world', 'blue-eyes-toon-dragon']::text[], '{"aggression":0.4,"signatureWeight":1.2,"removalBias":0.9,"backrowBias":1.3,"comebackBias":0.9}'::jsonb, '{"intro":"Pegasus smiles. \"Welcome to my delightful little performance.\"","summon":"Pegasus raises a hand. \"Let us add a touch of flair to the field.\"","spell":"Pegasus chuckles. \"A most entertaining twist, would you not agree?\"","trap":"Pegasus laughs. \"Ohoho, exactly as planned.\"","attack":"Pegasus gestures grandly. \"Take the stage and attack.\"","turn":"Pegasus draws elegantly. \"Now then, let the show continue.\"","loss":"Pegasus sighs. \"What an unexpectedly marvelous upset.\"","forfeit":"Pegasus chuckles. \"Ending the show so soon? If you exit now, I shall gladly accept the forfeit.\""}'::jsonb),
('char_yugi', 'Yugi Muto', 'Yugi steadies his hand. "I trust the heart of the cards."', 'Yugi stays calm. "If you leave now, I''ll take this duel by forfeit. Come back when you''re ready."', 'Yugi accepts the loss with respect. You beat one of the ladder''s steadiest duelists.', 'Yugi trusted the heart of the cards and found the line you could not answer.', ARRAY['dark-magician', 'dark-paladin', 'monster-reborn']::text[], '{"aggression":0.9,"signatureWeight":1.1,"removalBias":1,"backrowBias":0.6,"comebackBias":1.2}'::jsonb, '{"intro":"Yugi steadies his hand. \"I trust the heart of the cards.\"","summon":"Yugi focuses. \"Stand with me and guide this duel.\"","spell":"Yugi nods. \"There is always a path forward.\"","trap":"Yugi answers at once. \"I was ready for that.\"","attack":"Yugi calls out. \"Now, attack with everything you have!\"","turn":"Yugi draws calmly. \"My turn. I believe in this deck.\"","loss":"Yugi lowers his gaze. \"You dueled with real conviction.\"","forfeit":"Yugi stays calm. \"If you leave now, I''ll take this duel by forfeit. Come back when you''re ready.\""}'::jsonb),
('char_kaiba', 'Seto Kaiba', 'Kaiba smirks. "Prepare to be outclassed."', 'Kaiba scoffs. "Running away? Fine. Leave now and I''ll take the win by forfeit."', 'Kaiba is furious, which means you did what few duelists can: you crushed his ego.', 'Kaiba never let the pressure up and closed the ladder with brute force.', ARRAY['blue-eyes-white-dragon', 'blue-eyes-ultimate-dragon', 'crush-card-virus']::text[], '{"aggression":1.4,"signatureWeight":1.3,"removalBias":1.1,"backrowBias":0.2,"comebackBias":0.6}'::jsonb, '{"intro":"Kaiba smirks. \"Prepare to be outclassed.\"","summon":"Kaiba snaps the card onto the field. \"Witness real power.\"","spell":"Kaiba scoffs. \"This duel is already decided.\"","trap":"Kaiba laughs coldly. \"You walked straight into my setup.\"","attack":"Kaiba points ahead. \"Crush them.\"","turn":"Kaiba draws sharply. \"My turn. Try to keep up.\"","loss":"Kaiba clenches his jaw. \"Do not get used to it.\"","forfeit":"Kaiba scoffs. \"Running away? Fine. Leave now and I''ll take the win by forfeit.\""}'::jsonb)
on conflict (id) do update set
  name = excluded.name,
  intro_line = excluded.intro_line,
  forfeit_line = excluded.forfeit_line,
  stage_clear_line = excluded.stage_clear_line,
  defeat_line = excluded.defeat_line,
  signature_card_ids = excluded.signature_card_ids,
  ai_profile = excluded.ai_profile,
  voice_profile = excluded.voice_profile,
  updated_at = timezone('utc', now());

